1	import fs from "node:fs";
2	import path from "node:path";
3	import Link from "next/link";
4	
5	import CascadeTree3DClient from "@/components/CascadeTree3DClient";
6	import type { CascadeNode3D } from "@/components/CascadeTree3D";
7	
8	/**
9	 * /methods/graph — internal-only composition DAG view.
10	 *
11	 * The snapshot at /public/method-graph.json is materialized at build
12	 * time by `noosphere/scripts/dump_method_graph.py` (re-run on every
13	 * Vercel deploy). The page reads it from disk during server render and
14	 * passes the converted node list to <CascadeTree3DClient>.
15	 *
16	 * Color encoding (matches the snapshot's `color` field):
17	 *   • green — clean (no own risk, no inherited risk)
18	 *   • amber — risk inherited from a method in the closure
19	 *   • red — own active drift or fired failure mode
20	 *
21	 * The 3D primitive treats each node as having one parent, so when a
22	 * method depends on multiple methods (e.g. synthesize_conclusion → 3
23	 * deps) only the first edge is rendered in the 3D view; the full
24	 * adjacency list is shown as a text table beneath so no edge is hidden.
25	 */
26	
27	type GraphSnapshot = {
28	  schema: string;
29	  nodes: Array<{
30	    name: string;
31	    own_severity: string;
32	    inherited_severity: string;
33	    effective_severity: string;
34	    risk_inherited: boolean;
35	    inherited_from: string[];
36	    color: "green" | "amber" | "red";
37	    depth: number;
38	    description: string;
39	    version: string;
40	    status: string;
41	  }>;
42	  edges: Array<{ src: string; dst: string }>;
43	};
44	
45	function readSnapshot(): GraphSnapshot | null {
46	  const candidates = [
47	    path.join(process.cwd(), "public", "method-graph.json"),
48	    path.join(process.cwd(), "..", "theseus-codex", "public", "method-graph.json"),
49	  ];
50	  for (const p of candidates) {
51	    try {
52	      const text = fs.readFileSync(p, "utf8");
53	      return JSON.parse(text) as GraphSnapshot;
54	    } catch {
55	      // try next
56	    }
57	  }
58	  return null;
59	}
60	
61	function severityWeight(color: string): number {
62	  if (color === "red") return 1.0;
63	  if (color === "amber") return 0.65;
64	  return 0.4;
65	}
66	
67	function toCascadeNodes(snap: GraphSnapshot): CascadeNode3D[] {
68	  // Map: dst-method -> first src that depends on it. We invert
69	  // depends_on (src depends on dst) into parent edges where the deeper
70	  // composing method is the "child" in the radial layout.
71	  const firstDepFor = new Map<string, string>();
72	  for (const e of snap.edges) {
73	    if (!firstDepFor.has(e.src)) {
74	      firstDepFor.set(e.src, e.dst);
75	    }
76	  }
77	  return snap.nodes.map((n) => ({
78	    id: n.name,
79	    label: n.name,
80	    depth: n.depth,
81	    parentId: firstDepFor.get(n.name) ?? null,
82	    weight: severityWeight(n.color),
83	  }));
84	}
85	
86	export default async function MethodGraphPage() {
87	  const snap = readSnapshot();
88	  if (!snap) {
89	    return (
90	      <main className="container">
91	        <h1>Composition DAG</h1>
92	        <p style={{ color: "var(--parchment-dim)" }}>
93	          No graph snapshot found. Run{" "}
94	          <code className="mono">
95	            python noosphere/scripts/dump_method_graph.py --out theseus-codex/public/method-graph.json
96	          </code>{" "}
97	          to materialize one.
98	        </p>
99	      </main>
100	    );
101	  }
102	
103	  const nodes = toCascadeNodes(snap);
104	
105	  // Group adjacency for the table beneath the 3D view.
106	  const depsByMethod = new Map<string, string[]>();
107	  for (const e of snap.edges) {
108	    const arr = depsByMethod.get(e.src) ?? [];
109	    arr.push(e.dst);
110	    depsByMethod.set(e.src, arr);
111	  }
112	  for (const arr of depsByMethod.values()) arr.sort();
113	
114	  const counts = {
115	    green: snap.nodes.filter((n) => n.color === "green").length,
116	    amber: snap.nodes.filter((n) => n.color === "amber").length,
117	    red: snap.nodes.filter((n) => n.color === "red").length,
118	  };
119	
120	  return (
121	    <main className="container" style={{ paddingBottom: 64 }}>
122	      <header style={{ marginBottom: 16 }}>
123	        <Link href="/methods" className="mono" style={{ fontSize: "0.75rem" }}>
124	          ← methods
125	        </Link>
126	        <h1 style={{ marginTop: 8 }}>Composition DAG</h1>
127	        <p style={{ color: "var(--parchment-dim)", maxWidth: 720 }}>
128	          The firm's methods rest on each other. When a method drifts or has an
129	          unmitigated high-severity failure mode, every method that composes it
130	          inherits the risk. This view materializes the dependency graph from
131	          the <code className="mono">depends_on</code> declarations on each
132	          registered method and colors nodes by their effective severity.
133	        </p>
134	      </header>
135	
136	      <section
137	        aria-label="DAG legend"
138	        className="mono"
139	        style={{
140	          display: "flex",
141	          gap: 24,
142	          fontSize: "0.7rem",
143	          letterSpacing: "0.1em",
144	          textTransform: "uppercase",
145	          color: "var(--parchment-dim)",
146	          marginBottom: 12,
147	        }}
148	      >
149	        <span>
150	          <span style={{ color: "#7ab87a" }}>● </span>green ({counts.green}) — clean
151	        </span>
152	        <span>
153	          <span style={{ color: "#d4a017" }}>● </span>amber ({counts.amber}) — inherited risk
154	        </span>
155	        <span>
156	          <span style={{ color: "#c0392b" }}>● </span>red ({counts.red}) — own drift / failure
157	        </span>
158	      </section>
159	
160	      <CascadeTree3DClient nodes={nodes} height={520} />
161	
162	      <section style={{ marginTop: 24 }}>
163	        <h2 style={{ fontSize: "1rem", letterSpacing: "0.06em" }}>
164	          Adjacency
165	        </h2>
166	        <table
167	          style={{
168	            width: "100%",
169	            borderCollapse: "collapse",
170	            fontSize: "0.85rem",
171	          }}
172	        >
173	          <thead>
174	            <tr style={{ borderBottom: "1px solid var(--border)" }}>
175	              <th style={{ textAlign: "left", padding: "6px 8px" }}>Method</th>
176	              <th style={{ textAlign: "left", padding: "6px 8px" }}>Status</th>
177	              <th style={{ textAlign: "left", padding: "6px 8px" }}>
178	                Effective severity
179	              </th>
180	              <th style={{ textAlign: "left", padding: "6px 8px" }}>
181	                Depends on
182	              </th>
183	              <th style={{ textAlign: "left", padding: "6px 8px" }}>
184	                Inherited from
185	              </th>
186	            </tr>
187	          </thead>
188	          <tbody>
189	            {snap.nodes.map((n) => {
190	              const deps = depsByMethod.get(n.name) ?? [];
191	              return (
192	                <tr
193	                  key={n.name}
194	                  style={{ borderBottom: "1px solid var(--border-subtle, #2c2418)" }}
195	                >
196	                  <td style={{ padding: "6px 8px" }}>
197	                    <Link
198	                      href={`/methods/${encodeURIComponent(n.name)}`}
199	                      style={{ color: "var(--gold)" }}
200	                    >
201	                      {n.name}
202	                    </Link>
203	                  </td>
204	                  <td style={{ padding: "6px 8px", color: "var(--parchment-dim)" }}>
205	                    {n.status}
206	                  </td>
207	                  <td
208	                    style={{
209	                      padding: "6px 8px",
210	                      color:
211	                        n.color === "red"
212	                          ? "#c0392b"
213	                          : n.color === "amber"
214	                          ? "#d4a017"
215	                          : "var(--parchment-dim)",
216	                    }}
217	                  >
218	                    {n.effective_severity}
219	                  </td>
220	                  <td style={{ padding: "6px 8px", color: "var(--parchment-dim)" }}>
221	                    {deps.length === 0 ? "—" : deps.join(", ")}
222	                  </td>
223	                  <td style={{ padding: "6px 8px", color: "var(--parchment-dim)" }}>
224	                    {n.inherited_from.length === 0 ? "—" : n.inherited_from.join(", ")}
225	                  </td>
226	                </tr>
227	              );
228	            })}
229	          </tbody>
230	        </table>
231	      </section>
232	    </main>
233	  );
234	}
