11	  const csvData = toCSV(
12	    methods.map((m) => ({
13	      name: m.name,
14	      latestVersion: m.latestVersion,
15	      status: m.status,
16	      usageCount: m.usageCount,
17	      drift: m.driftState,
18	      driftLastObservedAt: m.driftLastObservedAt ?? "",
19	      description: m.description,
20	    })),
21	  );
22	
23	  function statusColor(status: string): string {
24	    switch (status) {
25	      case "active": return "var(--gold)";
26	      case "candidate": return "var(--parchment)";
27	      case "deprecated": return "var(--parchment-dim)";
28	      default: return "var(--parchment-dim)";
29	    }
30	  }
31	
32	  function driftColor(state: string): string {
33	    switch (state) {
34	      case "escalate":
35	        return "var(--ember, #c0392b)";
36	      case "warn":
37	        return "var(--amber, #d4a017)";
38	      case "insufficient":
39	        return "var(--parchment-dim)";
40	      case "ok":
41	        return "var(--parchment-dim)";
42	      default:
43	        return "var(--parchment-dim)";
44	    }
45	  }
46	
47	  function driftLabel(state: string): string {
48	    switch (state) {
49	      case "escalate":
50	        return "DRIFT — escalate";
51	      case "warn":
52	        return "DRIFT — warn";
53	      case "insufficient":
54	        return "n < 8";
55	      case "ok":
56	        return "stable";
57	      default:
58	        return "—";
59	    }
60	  }
61	
62	  return (
63	    <main style={{ maxWidth: "960px", margin: "0 auto", padding: "3rem 2rem" }}>
64	      <h1
65	        style={{
66	          fontFamily: "'Cinzel', serif",
67	          color: "var(--gold)",
68	          letterSpacing: "0.08em",
69	        }}
70	      >
71	        Methods registry
72	      </h1>
73	      <p style={{ color: "var(--parchment-dim)", marginBottom: "0.75rem", fontSize: "0.9rem" }}>
74	        Registered extraction and analysis methods with versioned documentation.
75	      </p>
76	
77	      <div style={{ display: "flex", gap: "0.75rem", marginBottom: "1.5rem", flexWrap: "wrap" }}>
78	        <Link href="/methods/candidates" className="btn" style={{ fontSize: "0.65rem", textDecoration: "none" }}>
79	          View candidates
80	        </Link>
81	        <a
82	          href={downloadHref(csvData, "text/csv")}
83	          download="methods.csv"
84	          className="btn"
85	          style={{ fontSize: "0.65rem", textDecoration: "none" }}
86	        >
87	          Download CSV
88	        </a>
89	        <a
90	          href={downloadHref(JSON.stringify(methods, null, 2), "application/json")}
91	          download="methods.json"
92	          className="btn"
93	          style={{ fontSize: "0.65rem", textDecoration: "none" }}
94	        >
95	          Download JSON
96	        </a>
97	      </div>
98	
99	      {methods.length === 0 ? (
100	        <div className="portal-card" style={{ padding: "1rem 1.25rem", color: "var(--parchment-dim)" }}>
101	          No methods registered yet. Methods are added when extraction pipelines are configured.
102	        </div>
103	      ) : (
104	        <ul style={{ listStyle: "none", padding: 0, margin: 0, display: "flex", flexDirection: "column", gap: "0.75rem" }}>
105	          {methods.map((m) => {
106	            const driftActive = m.driftState === "warn" || m.driftState === "escalate";
107	            return (
108	              <li
109	                key={m.name}
110	                className="portal-card"
111	                style={{
112	                  padding: "1rem 1.25rem",
113	                  borderLeft: driftActive
114	                    ? `3px solid ${driftColor(m.driftState)}`
115	                    : undefined,
116	                  background: driftActive
117	                    ? "rgba(192, 57, 43, 0.04)"
118	                    : undefined,
119	                }}
120	              >
121	                <div style={{ display: "flex", justifyContent: "space-between", flexWrap: "wrap", gap: "0.5rem" }}>
122	                  <Link
123	                    href={`/methods/${encodeURIComponent(m.name)}/${encodeURIComponent(m.latestVersion)}`}
124	                    style={{ color: "var(--gold)", textDecoration: "none", fontFamily: "'Cinzel', serif", fontSize: "0.85rem" }}
125	                  >
126	                    {m.name}
127	                  </Link>
128	                  <div style={{ display: "flex", gap: "0.75rem", alignItems: "baseline" }}>
129	                    <span
130	                      title={
131	                        m.driftLastObservedAt
132	                          ? `Last drift evaluation: ${m.driftLastObservedAt}`
133	                          : "No drift evaluation yet"
134	                      }
135	                      style={{
136	                        fontSize: "0.65rem",
137	                        color: driftColor(m.driftState),
138	                        textTransform: "uppercase",
139	                        fontWeight: driftActive ? 600 : 400,
140	                        letterSpacing: "0.08em",
141	                      }}
142	                    >
143	                      {driftLabel(m.driftState)}
144	                    </span>
145	                    <span style={{ fontSize: "0.65rem", color: statusColor(m.status), textTransform: "uppercase" }}>
146	                      {m.status}
147	                    </span>
148	                  </div>
149	                </div>
150	                <p style={{ marginTop: "0.35rem", color: "var(--parchment)", fontSize: "0.85rem" }}>
151	                  {m.description}
152	                </p>
153	                <div style={{ marginTop: "0.25rem", fontSize: "0.65rem", color: "var(--parchment-dim)" }}>
154	                  v{m.latestVersion} · {m.usageCount} uses
155	                </div>
156	              </li>
157	            );
158	          })}
159	        </ul>
160	      )}
161	    </main>
162	  );
163	}
