from __future__ import annotations

import contextvars
import hashlib
import json
import logging
import os
import subprocess
from datetime import datetime, timezone
from functools import wraps
from typing import Any, Callable
from uuid import uuid4

from pydantic import BaseModel

from noosphere.models import (
    CascadeEdgeRelation,
    Method,
    MethodImplRef,
    MethodInvocation,
    MethodType,
)
from noosphere.methods._hooks import _FAILURE_HOOKS, _POST_HOOKS, _PRE_HOOKS
from noosphere.methods._registry import REGISTRY
from noosphere.methods.composition import validate_depends_on

logger = logging.getLogger(__name__)

CORRELATION_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "CORRELATION_ID", default=""
)
TENANT_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "TENANT_ID", default="default"
)

_store_factory: Callable[..., Any] | None = None


def set_store_factory(factory: Callable[..., Any]) -> None:
    global _store_factory
    _store_factory = factory


def _get_store() -> Any:
    if _store_factory is not None:
        try:
            return _store_factory()
        except Exception:
            return None
    return None


def _canonical_json(obj: Any) -> str:
    if isinstance(obj, BaseModel):
        obj = obj.model_dump(mode="json")
    return json.dumps(obj, sort_keys=True, separators=(",", ":"), default=str)


def _current_git_sha() -> str:
    sha = os.environ.get("THESEUS_GIT_SHA")
    if sha:
        return sha
    try:
        result = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return "unknown"


def _current_correlation_id() -> str:
    return CORRELATION_ID.get()


def _current_tenant_id() -> str:
    return TENANT_ID.get()


def _validate_against_schema(schema: Any, data: Any) -> Any:
    if isinstance(schema, type) and issubclass(schema, BaseModel):
        if isinstance(data, schema):
            return data
        return schema.model_validate(data)
    if isinstance(schema, dict) and schema:
        try:
            import jsonschema as _js

            _js.validate(data, schema)
        except ImportError:
            pass
    return data


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _run_failure_path(
    spec: Method,
    inv: MethodInvocation,
    validated_input: Any,
    exc: BaseException,
) -> None:
    inv = inv.model_copy(
        update={
            "ended_at": _utcnow(),
            "succeeded": False,
            "error_kind": type(exc).__name__,
        }
    )
    for hook_name, hook in _FAILURE_HOOKS:
        try:
            hook(spec, inv, validated_input, exc)
        except Exception:
            logger.exception("Failure hook %s raised", hook_name)
    store = _get_store()
    if store is not None:
        try:
            store.insert_method_invocation(inv)
        except Exception:
            logger.exception("Failed to persist invocation")


def register_method(
    *,
    name: str,
    version: str,
    method_type: MethodType,
    input_schema: Any,
    output_schema: Any,
    description: str,
    rationale: str,
    preconditions: list[str] | tuple[str, ...] = (),
    postconditions: list[str] | tuple[str, ...] = (),
    dependencies: list[tuple[str, str]] | tuple[tuple[str, str], ...] = (),
    depends_on: list[str] | tuple[str, ...] = (),
    owner: str,
    status: str = "active",
    nondeterministic: bool = False,
    emits_edges: list[CascadeEdgeRelation] | tuple[CascadeEdgeRelation, ...] = (),
) -> Callable:
    def decorator(fn: Callable) -> Callable:
        if isinstance(input_schema, type) and issubclass(input_schema, BaseModel):
            in_schema_dict = input_schema.model_json_schema()
        elif isinstance(input_schema, dict):
            in_schema_dict = input_schema
        else:
            in_schema_dict = {}

        if isinstance(output_schema, type) and issubclass(output_schema, BaseModel):
            out_schema_dict = output_schema.model_json_schema()
        elif isinstance(output_schema, dict):
            out_schema_dict = output_schema
        else:
            out_schema_dict = {}

        impl = MethodImplRef(
            module=fn.__module__,
            fn_name=fn.__qualname__,
            git_sha=_current_git_sha(),
            image_digest=None,
        )

        spec_for_hash = {
            "name": name,
            "version": version,
            "method_type": method_type.value,
            "input_schema": in_schema_dict,
            "output_schema": out_schema_dict,
            "description": description,
            "rationale": rationale,
            "preconditions": list(preconditions),
            "postconditions": list(postconditions),
            "dependencies": [list(d) for d in dependencies],
            "implementation": impl.model_dump(mode="json"),
            "owner": owner,
            "status": status,
            "nondeterministic": nondeterministic,
        }

        method_id = hashlib.sha256(
            _canonical_json(spec_for_hash).encode()
        ).hexdigest()[:32]

        spec = Method(
            method_id=method_id,
            name=name,
            version=version,
            method_type=method_type,
            input_schema=in_schema_dict,
            output_schema=out_schema_dict,
            description=description,
            rationale=rationale,
            preconditions=list(preconditions),
            postconditions=list(postconditions),
            dependencies=list(dependencies),
            implementation=impl,
            owner=owner,
            status=status,
            nondeterministic=nondeterministic,
            created_at=_utcnow(),
        )

        @wraps(fn)
        def wrapped(input_data: Any) -> Any:
            validated_input = _validate_against_schema(input_schema, input_data)
            input_hash = hashlib.sha256(
                _canonical_json(validated_input).encode()
            ).hexdigest()

            inv = MethodInvocation(
                id=str(uuid4()),
                method_id=spec.method_id,
                input_hash=input_hash,
                output_hash="",
                started_at=_utcnow(),
                ended_at=None,
                succeeded=False,
                error_kind=None,
                correlation_id=_current_correlation_id(),
                tenant_id=_current_tenant_id(),
            )

            try:
                for _hook_name, hook in _PRE_HOOKS:
                    hook(spec, inv, validated_input)
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

            try:
                result = fn(validated_input)
                _validate_against_schema(output_schema, result)
                output_hash = hashlib.sha256(
                    _canonical_json(result).encode()
                ).hexdigest()
                inv = inv.model_copy(
                    update={
                        "ended_at": _utcnow(),
                        "succeeded": True,
                        "output_hash": output_hash,
                    }
                )

                for hook_name, hook in _POST_HOOKS:
                    try:
                        hook(spec, inv, validated_input, result)
                    except Exception:
                        logger.exception("Post-hook %s raised", hook_name)

                store = _get_store()
                if store is not None:
                    try:
                        store.insert_method_invocation(inv)
                    except Exception:
                        logger.exception("Failed to persist invocation")

                return result
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

        wrapped.__method_spec__ = spec  # type: ignore[attr-defined]

        REGISTRY.register(spec, wrapped)

        # Composition DAG: declared depends_on names must already be
        # registered. Decoration-time check so a typo fails CI rather
        # than silently leaving a ghost edge in the graph.
        if depends_on:
            validate_depends_on(
                REGISTRY.known_method_names(), name, list(depends_on)
            )
            REGISTRY.set_depends_on(name, list(depends_on))
        else:
            # Always seed the side table so build_dag() sees this node.
            REGISTRY.set_depends_on(name, [])

        if emits_edges:
            REGISTRY.set_emits_edges(method_id, list(emits_edges))

        store = _get_store()
        if store is not None:
            try:
                store.insert_method(spec)
            except Exception:
                logger.exception("Failed to persist method spec")

        return wrapped

    return decorator

from __future__ import annotations

from typing import Callable

from noosphere.models import CascadeEdgeRelation, Method


class MethodCollisionError(Exception):
    pass


class MethodNotFoundError(Exception):
    pass


def _parse_semver(version: str) -> tuple[int, ...]:
    parts: list[int] = []
    for p in version.split("."):
        try:
            parts.append(int(p))
        except ValueError:
            parts.append(0)
    return tuple(parts)


class MethodRegistry:
    def __init__(self) -> None:
        self._specs: dict[tuple[str, str], Method] = {}
        self._fns: dict[tuple[str, str], Callable] = {}
        self._emits_edges: dict[str, list[CascadeEdgeRelation]] = {}
        # name -> list of dependency method names (composition DAG).
        # Keyed on bare name because the DAG is about method identity,
        # not about a particular pinned version.
        self._depends_on: dict[str, list[str]] = {}

    def register(self, spec: Method, fn: Callable) -> None:
        key = (spec.name, spec.version)
        if key in self._specs:
            raise MethodCollisionError(
                f"Method {spec.name} v{spec.version} already registered"
            )
        self._specs[key] = spec
        self._fns[key] = fn

    def set_emits_edges(
        self, method_id: str, edges: list[CascadeEdgeRelation]
    ) -> None:
        self._emits_edges[method_id] = list(edges)

    def get_emits_edges(self, method_id: str) -> list[CascadeEdgeRelation]:
        return self._emits_edges.get(method_id, [])

    # ── composition DAG side table ────────────────────────────────────

    def set_depends_on(self, name: str, deps: list[str]) -> None:
        self._depends_on[name] = list(deps)

    def get_depends_on(self, name: str) -> list[str]:
        return list(self._depends_on.get(name, []))

    def iter_depends_on(self):
        for name, deps in self._depends_on.items():
            yield name, list(deps)

    def known_method_names(self) -> set[str]:
        return {n for (n, _v) in self._specs.keys()}

    def get(
        self,
        name: str,
        version: str = "latest",
        include_retired: bool = False,
    ) -> tuple[Method, Callable]:
        if version != "latest":
            key = (name, version)
            if key not in self._specs:
                raise MethodNotFoundError(
                    f"Method {name} v{version} not found"
                )
            spec = self._specs[key]
            if spec.status == "retired" and not include_retired:
                raise MethodNotFoundError(
                    f"Method {name} v{version} is retired"
                )
            return spec, self._fns[key]

        candidates: list[tuple[str, Method]] = []
        for (n, v), spec in self._specs.items():
            if n != name:
                continue
            if spec.status == "retired" and not include_retired:
                continue
            candidates.append((v, spec))

        if not candidates:
            raise MethodNotFoundError(f"No active method found for {name}")

        candidates.sort(key=lambda x: _parse_semver(x[0]), reverse=True)
        best_version = candidates[0][0]
        return self._specs[(name, best_version)], self._fns[(name, best_version)]

    def list(self, status_filter: str | None = None) -> list[Method]:
        specs = list(self._specs.values())
        if status_filter is not None:
            specs = [s for s in specs if s.status == status_filter]
        return specs


REGISTRY = MethodRegistry()

"""
Injectable embedding clients with on-disk cache keyed by (model, text hash).
"""

from __future__ import annotations

import hashlib
import json
import random
from pathlib import Path
from typing import Any, Protocol, runtime_checkable

try:
    import numpy as np
except ImportError:  # pragma: no cover - fallback is for broken local wheels.
    np = None  # type: ignore[assignment]


def _text_hash(model: str, text: str) -> str:
    h = hashlib.sha256()
    h.update(model.encode("utf-8"))
    h.update(b"\x00")
    h.update(text.encode("utf-8"))
    return h.hexdigest()


@runtime_checkable
class EmbeddingClient(Protocol):
    def encode(self, texts: list[str]) -> list[list[float]]: ...

    @property
    def model_name(self) -> str: ...


class DiskEmbeddingCache:
    """On-disk cache: one JSON file per (model, exact text)."""

    def __init__(self, root: Path) -> None:
        self.root = root
        self.root.mkdir(parents=True, exist_ok=True)

    def path(self, model: str, text: str) -> Path:
        return self.root / f"{_text_hash(model, text)}.json"

    def get(self, model: str, text: str) -> list[float] | None:
        p = self.path(model, text)
        if not p.is_file():
            return None
        data = json.loads(p.read_text(encoding="utf-8"))
        vec = data.get("embedding")
        if isinstance(vec, list):
            return [float(x) for x in vec]
        return None

    def put(self, model: str, text: str, vector: list[float]) -> None:
        p = self.path(model, text)
        p.write_text(
            json.dumps({"model": model, "embedding": vector}, separators=(",", ":")),
            encoding="utf-8",
        )


class SentenceTransformersClient:
    """Local sentence-transformers backend."""

    def __init__(
        self,
        model_name: str,
        *,
        device: str | None = None,
        cache_dir: Path | None = None,
    ) -> None:
        from sentence_transformers import SentenceTransformer

        self._model_name = model_name
        self._cache = DiskEmbeddingCache(cache_dir) if cache_dir is not None else None
        kwargs: dict[str, Any] = {}
        if device:
            kwargs["device"] = device
        self._model = SentenceTransformer(model_name, **kwargs)

    @property
    def model_name(self) -> str:
        return self._model_name

    def encode(self, texts: list[str]) -> list[list[float]]:
        out: list[list[float]] = []
        for t in texts:
            if self._cache is not None:
                hit = self._cache.get(self._model_name, t)
                if hit is not None:
                    out.append(hit)
                    continue
            vec_np = self._model.encode(
                [t],
                convert_to_numpy=np is not None,
                show_progress_bar=False,
            )
            if np is not None:
                vec = np.asarray(vec_np[0], dtype=float).tolist()
            else:
                vec = [float(x) for x in vec_np[0]]
            if self._cache is not None:
                self._cache.put(self._model_name, t, vec)
            out.append(vec)
        return out


class MockEmbeddingClient:
    """Deterministic fake vectors for tests (no model download)."""

    def __init__(self, model_name: str = "mock-embed", dim: int = 8) -> None:
        self._model_name = model_name
        self._dim = dim

    @property
    def model_name(self) -> str:
        return self._model_name

    def encode(self, texts: list[str]) -> list[list[float]]:
        out: list[list[float]] = []
        for t in texts:
            seed = int(hashlib.sha256(t.encode()).hexdigest()[:8], 16)
            if np is not None:
                rng = np.random.default_rng(seed)
                out.append(rng.standard_normal(self._dim).astype(float).tolist())
            else:
                rng = random.Random(seed)
                out.append([rng.gauss(0.0, 1.0) for _ in range(self._dim)])
        return out


def default_cache_dir() -> Path:
    from noosphere.config import get_settings

    d = get_settings().data_dir / "embedding_cache"
    d.mkdir(parents=True, exist_ok=True)
    return d


def sentence_transformers_client_from_settings() -> SentenceTransformersClient:
    from noosphere.config import get_settings

    s = get_settings()
    return SentenceTransformersClient(
        s.embedding_model_name,
        device=s.embedding_device or None,
        cache_dir=default_cache_dir(),
    )

"""CLI commands for the Method Registry subsystem."""

from __future__ import annotations

import json
from datetime import datetime, timezone
from typing import Optional

import click
from rich.console import Console
from rich.table import Table

console = Console()


def _get_store():
    from noosphere.cli import get_orchestrator
    return get_orchestrator(None).store


def _render(obj, as_json: bool) -> None:
    if as_json:
        click.echo(json.dumps(obj, indent=2, default=str))


@click.group("methods")
def cli() -> None:
    """Method registry: list, inspect, run, and diff registered methods."""


@cli.command("list")
@click.option("--status", "status_filter", type=str, default=None,
              help="Filter by status (experimental, active, deprecated, retired)")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def list_methods(status_filter: Optional[str], as_json: bool) -> None:
    """List all registered methods."""
    from noosphere.methods import REGISTRY

    methods = REGISTRY.list(status_filter=status_filter)
    if as_json:
        _render([{"name": m.name, "version": m.version, "status": m.status,
                  "type": m.method_type.value, "description": m.description}
                 for m in methods], True)
        return
    if not methods:
        console.print("[yellow]No methods registered.[/yellow]")
        return
    table = Table(title="Registered Methods", show_header=True)
    table.add_column("Name", style="cyan")
    table.add_column("Version")
    table.add_column("Status")
    table.add_column("Type")
    table.add_column("Description", max_width=50)
    for m in methods:
        table.add_row(m.name, m.version, m.status, m.method_type.value,
                      m.description[:50])
    console.print(table)


@cli.command("show")
@click.argument("ref")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def show_method(ref: str, as_json: bool) -> None:
    """Show details of a method. REF is name or name@version."""
    from noosphere.methods import REGISTRY

    name, version = (ref.split("@", 1) + ["latest"])[:2]
    method, _fn = REGISTRY.get(name, version=version)
    if as_json:
        _render(method.model_dump(), True)
        return
    table = Table(title=f"Method: {method.name}@{method.version}", show_header=False)
    for field in ("method_id", "name", "version", "method_type", "status",
                  "owner", "description", "rationale"):
        val = getattr(method, field)
        table.add_row(field, str(val) if not hasattr(val, "value") else val.value)
    table.add_row("preconditions", ", ".join(method.preconditions) or "—")
    table.add_row("postconditions", ", ".join(method.postconditions) or "—")
    console.print(table)


@cli.command("run")
@click.argument("ref")
@click.option("--input", "input_json", required=True, help="JSON input for the method")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def run_method(ref: str, input_json: str, as_json: bool) -> None:
    """Run a method. REF is name or name@version."""
    from noosphere.methods import REGISTRY

    name, version = (ref.split("@", 1) + ["latest"])[:2]
    _method, fn = REGISTRY.get(name, version=version)
    payload = json.loads(input_json)
    result = fn(payload)
    if as_json:
        _render(result if isinstance(result, (dict, list)) else str(result), True)
        return
    console.print(result)


@cli.command("diff")
@click.argument("ref_a")
@click.argument("ref_b")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def diff_methods(ref_a: str, ref_b: str, as_json: bool) -> None:
    """Diff two method versions. Each REF is name@version."""
    from noosphere.methods import REGISTRY

    name_a, ver_a = (ref_a.split("@", 1) + ["latest"])[:2]
    name_b, ver_b = (ref_b.split("@", 1) + ["latest"])[:2]
    m_a, _ = REGISTRY.get(name_a, version=ver_a)
    m_b, _ = REGISTRY.get(name_b, version=ver_b)
    d_a, d_b = m_a.model_dump(), m_b.model_dump()
    diffs = {k: {"old": d_a[k], "new": d_b[k]}
             for k in d_a if d_a.get(k) != d_b.get(k)}
    if as_json:
        _render(diffs, True)
        return
    if not diffs:
        console.print("[green]Methods are identical.[/green]")
        return
    table = Table(title=f"Diff: {ref_a} ↔ {ref_b}", show_header=True)
    table.add_column("Field", style="cyan")
    table.add_column("Old")
    table.add_column("New")
    for field, vals in diffs.items():
        table.add_row(field, str(vals["old"])[:60], str(vals["new"])[:60])
    console.print(table)


@cli.group("failures")
def failures_cli() -> None:
    """Curate and validate per-method failure-mode catalogs."""


@failures_cli.command("init")
@click.argument("method_name")
def failures_init(method_name: str) -> None:
    """Scaffold a `<method>.FAILURES.yaml` next to the method source."""
    from noosphere.methods.failure_modes import (
        FailureCatalogError,
        scaffold_catalog,
    )

    try:
        path = scaffold_catalog(method_name)
    except FailureCatalogError as exc:
        raise click.ClickException(str(exc))
    console.print(
        f"[green]Scaffolded[/green] {path} — edit it to add real entries."
    )


@failures_cli.command("lint")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def failures_lint(as_json: bool) -> None:
    """Validate every failure-mode catalog. Non-zero exit on any error."""
    from noosphere.methods.failure_modes import (
        FailureCatalogError,
        lint_all,
    )

    try:
        catalogs = lint_all()
    except FailureCatalogError as exc:
        raise click.ClickException(str(exc))

    summary = [
        {
            "method": method,
            "modes": (
                "deliberately-empty"
                if catalog.failures == "deliberately-empty"
                else len(catalog.modes)
            ),
            "high_severity": sum(
                1 for m in catalog.modes if m.severity == "high"
            ),
            "public_entries": sum(1 for m in catalog.modes if m.public),
        }
        for method, catalog in catalogs.items()
    ]
    if as_json:
        _render(summary, True)
        return

    if not summary:
        console.print("[yellow]No failure-mode catalogs found.[/yellow]")
        return
    table = Table(title="Failure-mode catalogs", show_header=True)
    table.add_column("Method", style="cyan")
    table.add_column("Modes")
    table.add_column("High-severity")
    table.add_column("Public entries")
    for row in summary:
        table.add_row(
            row["method"],
            str(row["modes"]),
            str(row["high_severity"]),
            str(row["public_entries"]),
        )
    console.print(table)


@cli.command("extract-candidates")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def extract_candidates(as_json: bool) -> None:
    """Scan the registry for candidate methods needing review."""
    from noosphere.methods import REGISTRY

    candidates = [m for m in REGISTRY.list() if m.status == "experimental"]
    if as_json:
        _render([{"name": m.name, "version": m.version, "owner": m.owner}
                 for m in candidates], True)
        return
    if not candidates:
        console.print("[green]No experimental candidates.[/green]")
        return
    table = Table(title="Method Candidates", show_header=True)
    table.add_column("Name", style="cyan")
    table.add_column("Version")
    table.add_column("Owner")
    for m in candidates:
        table.add_row(m.name, m.version, m.owner)
    console.print(table)


# ── Track record (method ↔ resolved forecasts) ─────────────────────────────


def _open_codex():
    from noosphere.codex_bridge import (
        REAL_DICT_CURSOR,
        _open_codex_connection,
        _resolve_codex_db_url,
    )

    url = _resolve_codex_db_url(None)
    conn = _open_codex_connection(url)
    return conn, REAL_DICT_CURSOR


def _resolve_org_id(cur, organization_slug: Optional[str]) -> Optional[str]:
    if not organization_slug:
        return None
    cur.execute(
        'SELECT id FROM "Organization" WHERE slug = %s',
        (organization_slug,),
    )
    row = cur.fetchone()
    if not row:
        raise click.ClickException(
            f"Organization slug not found: {organization_slug}"
        )
    return row["id"] if isinstance(row, dict) else row[0]


def _conclusions_with_profiles(cur, *, organization_id: Optional[str], limit: int):
    """Conclusions that have at least one MethodologyProfile attached, either
    directly or via the upload bridge."""
    cur.execute(
        '''SELECT DISTINCT c.id AS id,
                  c."organizationId" AS org_id,
                  c.text             AS text,
                  c."topicHint"      AS topic_hint
             FROM "Conclusion" c
             JOIN "MethodologyProfile" mp
                  ON mp."conclusionId" = c.id
                  OR mp."uploadId" IN (
                       SELECT cs."uploadId" FROM "ConclusionSource" cs
                        WHERE cs."conclusionId" = c.id
                  )
            WHERE (%s IS NULL OR c."organizationId" = %s)
            ORDER BY c.id
            LIMIT %s''',
        (organization_id, organization_id, int(limit)),
    )
    return list(cur.fetchall())


def _profiles_for(cur, *, organization_id: str, conclusion_id: str):
    from noosphere.evaluation.mqs import MethodologyProfileSummary

    cur.execute(
        '''SELECT mp."patternType", mp.title, mp.summary,
                  mp."reasoningMoves", mp."transferTargets",
                  mp.assumptions, mp."failureModes", mp.confidence
             FROM "MethodologyProfile" mp
             LEFT JOIN "ConclusionSource" cs ON cs."uploadId" = mp."uploadId"
            WHERE mp."organizationId" = %s
              AND (mp."conclusionId" = %s OR cs."conclusionId" = %s)
            ORDER BY mp.confidence DESC
            LIMIT 8''',
        (organization_id, conclusion_id, conclusion_id),
    )

    def _aslist(raw):
        if raw is None:
            return []
        if isinstance(raw, list):
            return [str(x) for x in raw if x is not None]
        if isinstance(raw, str):
            try:
                v = json.loads(raw)
                return [str(x) for x in v if x is not None] if isinstance(v, list) else []
            except Exception:
                return []
        return []

    out = []
    for row in cur.fetchall():
        out.append(
            MethodologyProfileSummary(
                pattern_type=(row.get("patternType") if isinstance(row, dict) else row[0]) or "",
                title=(row.get("title") if isinstance(row, dict) else row[1]) or "",
                summary=(row.get("summary") if isinstance(row, dict) else row[2]) or "",
                reasoning_moves=_aslist(
                    row.get("reasoningMoves") if isinstance(row, dict) else row[3]
                ),
                transfer_targets=_aslist(
                    row.get("transferTargets") if isinstance(row, dict) else row[4]
                ),
                assumptions=_aslist(
                    row.get("assumptions") if isinstance(row, dict) else row[5]
                ),
                failure_modes=_aslist(
                    row.get("failureModes") if isinstance(row, dict) else row[6]
                ),
                confidence=float(
                    (row.get("confidence") if isinstance(row, dict) else row[7]) or 0.5
                ),
            )
        )
    return out


@cli.command("track-record")
@click.option(
    "--organization-slug",
    type=str,
    default=None,
    help="Restrict to a single organization (default: all orgs).",
)
@click.option(
    "--rebuild/--no-rebuild",
    default=False,
    help="Run the linker + aggregator pipeline before printing. Idempotent.",
)
@click.option(
    "--judge",
    "judge_name",
    type=click.Choice(["stub"]),
    default="stub",
    help="Linker judge to use. Only the deterministic stub is exposed via "
    "the CLI; production callers may construct their own MethodLinkerJudge.",
)
@click.option(
    "--limit",
    type=int,
    default=500,
    help="Maximum conclusions to (re)link in this run.",
)
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def track_record(
    organization_slug: Optional[str],
    rebuild: bool,
    judge_name: str,
    limit: int,
    as_json: bool,
) -> None:
    """Show per-method track record. With --rebuild, first re-link every
    conclusion to its methods and re-aggregate every (method, domain) cell.
    Both passes are idempotent: re-running on a quiet DB is a no-op modulo
    `updatedAt`."""
    from noosphere.evaluation.method_outcome_linker import (
        StubMethodLinkerJudge,
        infer_links,
        registry_view,
        upsert_links,
    )
    from noosphere.evaluation.method_track_record import (
        aggregate,
        fetch_method_keys,
        fetch_resolved_rows,
        upsert_track_record,
    )

    conn, real_dict_cursor = _open_codex()
    try:
        cur = conn.cursor(cursor_factory=real_dict_cursor)
        organization_id = _resolve_org_id(cur, organization_slug)

        if rebuild:
            registry = registry_view()
            judge = StubMethodLinkerJudge()
            now = datetime.now(timezone.utc)

            conclusions = _conclusions_with_profiles(
                cur, organization_id=organization_id, limit=limit
            )
            linked = 0
            for c in conclusions:
                cid = c["id"] if isinstance(c, dict) else c[0]
                org = c["org_id"] if isinstance(c, dict) else c[1]
                text = (c.get("text") if isinstance(c, dict) else c[2]) or ""
                topic = (c.get("topic_hint") if isinstance(c, dict) else c[3]) or ""
                profiles = _profiles_for(cur, organization_id=org, conclusion_id=cid)
                if not profiles:
                    continue
                links = infer_links(
                    conclusion_id=cid,
                    conclusion_text=text,
                    topic_hint=topic,
                    profiles=profiles,
                    registry_methods=registry,
                    judge=judge,
                )
                if not links:
                    continue
                linked += upsert_links(
                    cur,
                    organization_id=org,
                    conclusion_id=cid,
                    links=links,
                    now=now,
                )

            # Aggregate per (org, method, version). Walk every distinct
            # method seen in ConclusionMethod so we don't miss methods
            # that no longer match a registered name.
            cur.execute(
                'SELECT id FROM "Organization"'
                + (' WHERE id = %s' if organization_id else ''),
                (organization_id,) if organization_id else (),
            )
            org_ids = [
                (row.get("id") if isinstance(row, dict) else row[0])
                for row in cur.fetchall()
            ]
            aggregated = 0
            for org_id in org_ids:
                for (m_name, m_version) in fetch_method_keys(
                    cur, organization_id=org_id
                ):
                    rows = fetch_resolved_rows(
                        cur,
                        organization_id=org_id,
                        method_name=m_name,
                        method_version=m_version,
                    )
                    records = aggregate(
                        organization_id=org_id,
                        method_name=m_name,
                        method_version=m_version,
                        rows=rows,
                        now=now,
                    )
                    # Even when rows is empty, emit a sample_size=0 row
                    # for every (method, domain="") so downstream UI sees
                    # the method exists but has no record yet.
                    if not records:
                        records = aggregate(
                            organization_id=org_id,
                            method_name=m_name,
                            method_version=m_version,
                            rows=[],
                            now=now,
                        )
                        if not records:
                            from noosphere.evaluation.method_track_record import (
                                TrackRecord,
                                TRACK_RECORD_SCHEMA,
                            )

                            records = [
                                TrackRecord(
                                    organization_id=org_id,
                                    method_name=m_name,
                                    method_version=m_version,
                                    domain="",
                                    sample_size=0,
                                    weighted_brier=None,
                                    calibration_slope=None,
                                    calibration_slope_ci_low=None,
                                    calibration_slope_ci_high=None,
                                    severity_pass_rate=None,
                                    evidence={
                                        "schema": TRACK_RECORD_SCHEMA,
                                        "prediction_ids": [],
                                        "conclusion_ids": [],
                                    },
                                    computed_at=now,
                                )
                            ]
                    for record in records:
                        upsert_track_record(cur, record)
                        aggregated += 1
            conn.commit()
            click.echo(
                json.dumps(
                    {"linked": linked, "aggregated": aggregated, "judge": judge_name},
                    indent=2,
                )
            )

        # Print whatever is in MethodTrackRecord (post-rebuild or cached).
        cur.execute(
            '''SELECT "organizationId", "methodName", "methodVersion", domain,
                      "sampleSize", "weightedBrier",
                      "calibrationSlope", "calibrationSlopeCiLow",
                      "calibrationSlopeCiHigh", "severityPassRate",
                      "computedAt"
                 FROM "MethodTrackRecord"
                WHERE (%s IS NULL OR "organizationId" = %s)
                ORDER BY "methodName", "methodVersion", domain''',
            (organization_id, organization_id),
        )
        rows = list(cur.fetchall())

        if as_json:
            click.echo(
                json.dumps(
                    [
                        {
                            "organization_id": r["organizationId"]
                            if isinstance(r, dict) else r[0],
                            "method_name": r["methodName"]
                            if isinstance(r, dict) else r[1],
                            "method_version": r["methodVersion"]
                            if isinstance(r, dict) else r[2],
                            "domain": r["domain"] if isinstance(r, dict) else r[3],
                            "sample_size": r["sampleSize"]
                            if isinstance(r, dict) else r[4],
                            "weighted_brier": r["weightedBrier"]
                            if isinstance(r, dict) else r[5],
                            "calibration_slope": r["calibrationSlope"]
                            if isinstance(r, dict) else r[6],
                            "calibration_slope_ci_low": r["calibrationSlopeCiLow"]
                            if isinstance(r, dict) else r[7],
                            "calibration_slope_ci_high": r["calibrationSlopeCiHigh"]
                            if isinstance(r, dict) else r[8],
                            "severity_pass_rate": r["severityPassRate"]
                            if isinstance(r, dict) else r[9],
                            "computed_at": str(
                                r["computedAt"] if isinstance(r, dict) else r[10]
                            ),
                        }
                        for r in rows
                    ],
                    indent=2,
                    default=str,
                )
            )
            return

        if not rows:
            console.print(
                "[yellow]No track records yet. Run with --rebuild.[/yellow]"
            )
            return

        table = Table(title="Method Track Records", show_header=True)
        table.add_column("Method", style="cyan")
        table.add_column("v")
        table.add_column("Domain")
        table.add_column("n")
        table.add_column("Brier")
        table.add_column("Slope")
        table.add_column("CI")
        table.add_column("Sev pass")
        for r in rows:
            def _g(key, idx):
                return r[key] if isinstance(r, dict) else r[idx]

            slope = _g("calibrationSlope", 6)
            lo = _g("calibrationSlopeCiLow", 7)
            hi = _g("calibrationSlopeCiHigh", 8)
            ci = (
                f"[{lo:.2f}, {hi:.2f}]"
                if (lo is not None and hi is not None)
                else "—"
            )
            brier = _g("weightedBrier", 5)
            sev = _g("severityPassRate", 9)
            table.add_row(
                str(_g("methodName", 1)),
                str(_g("methodVersion", 2)),
                str(_g("domain", 3) or "—"),
                str(_g("sampleSize", 4)),
                f"{brier:.3f}" if brier is not None else "—",
                f"{slope:.2f}" if slope is not None else "—",
                ci,
                f"{sev:.0%}" if sev is not None else "—",
            )
        console.print(table)
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()

