model ConclusionMethod {
  id             String @id @default(cuid())
  organizationId String
  conclusionId   String

  /// Reference into the in-process method registry. Stored as
  /// (name, version) rather than a foreign key because the registry is a
  /// Python decorator catalog, not a DB table.
  methodName    String
  methodVersion String

  /// In [0, 1]. How much this method contributed to the conclusion. The
  /// linker is allowed to assign multiple methods weight 1.0 — this is
  /// not a softmax over methods.
  weight Float @default(1.0)

  /// Domain the conclusion sits in (e.g. "forecasting", "policy"). Empty
  /// string when unknown. Track records are computed per-domain.
  domain String @default("")

  /// Free-form rationale from the linker (LLM judge or stub). Useful for
  /// audit; not load-bearing.
  rationale String @default("")

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  conclusion   Conclusion   @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@unique([conclusionId, methodName, methodVersion])
  @@index([organizationId, methodName, methodVersion])
  @@index([methodName, methodVersion])
}

// ── Materialized per-method track record ─────────────────────────────────
//
// Rolled up from resolved ForecastPredictions linked to each method through
// ConclusionMethod, weighted by `ConclusionMethod.weight`. Materialized
// rather than computed on every page load because the join goes through a
// chain of three tables and the aggregation includes a bootstrap CI on the
// calibration slope. The materialization job (`noosphere methods
// track-record --rebuild`) is idempotent: it upserts on
// (organizationId, methodName, methodVersion, domain).
model MethodTrackRecord {
  id             String @id @default(cuid())
  organizationId String

  methodName    String
  methodVersion String

  /// Empty string for "no domain label". Track records are NEVER smoothed
  /// across domains — one row per domain.
  domain String @default("")

  /// Number of resolved ForecastPredictions feeding this row. Hard filter:
  /// unresolved predictions are excluded entirely.
  sampleSize Int

  /// Σ(weight·brier) / Σ(weight). Null when sampleSize == 0.
  weightedBrier Float?

  /// OLS slope of outcome ~ probability over resolved predictions, with a
  /// non-parametric bootstrap CI. Null when the slope is undefined
  /// (sampleSize < 2 or zero variance in probabilities).
  calibrationSlope       Float?
  calibrationSlopeCiLow  Float?
  calibrationSlopeCiHigh Float?

  /// Fraction of source conclusions whose MQS severity sub-score is at
  /// or above the published threshold (0.5). Null when no MQS data.
  severityPassRate Float?

  /// Audit blob: bootstrap iterations, threshold used, source ids, etc.
  evidence Json

  computedAt DateTime @default(now())
  createdAt  DateTime @default(now())
  updatedAt  DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@unique([organizationId, methodName, methodVersion, domain])
  @@index([methodName, methodVersion])
  @@index([organizationId, computedAt])
}

